import { execSync } from 'node:child_process';
import { writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');
const outPath = join(root, 'src/lib/database.types.ts');

const header = `/**
 * Generated by \`npm run supabase:types\` — do not edit by hand.
 *
 * Regenerate after schema migrations (local Supabase must be running, or use
 * \`supabase gen types typescript --linked\` and paste output).
 *
 * PostgREST uses snake_case column names. Spec prose may use camelCase
 * (userId → user_id, groupId → group_id, intervalDays → interval_days).
 *
 * DB-managed (triggers): routines.last_completed_at (from routine_completions).
 * Client uses anon key only; RLS enforces per-user access — never service_role in the app.
 */

`;

const types = execSync('supabase gen types typescript --local', {
	cwd: root,
	encoding: 'utf8',
	stdio: ['ignore', 'pipe', 'inherit']
});

writeFileSync(outPath, header + types, 'utf8');
console.log(`Wrote ${outPath}`);
